"use strict";const hamburger=document.querySelector(".header__burger"),menu=document.querySelector(".header__menu");hamburger.addEventListener("click",(function(){menu.classList.toggle("header__menu--open"),hamburger.classList.toggle("header__burger--cross")})),window.addEventListener("click",(e=>{const t=e.target;t.closest(".header__menu")||t.closest(".header__burger")||(menu.classList.remove("header__menu--open"),hamburger.classList.remove("header__burger--cross"))}));const footerAccordeonContent=Array.from(document.querySelectorAll(".footer__content-accordeon"));function accordeon(e){e.preventDefault;let t=e.target.closest(".footer__content-accordeon"),o=e.target.nextElementSibling;t.classList.toggle("footer__content-accordeon--active"),t.classList.contains("footer__content-accordeon--active")?o.style.maxHeight=o.scrollHeight+"px":o.style.maxHeight=0}footerAccordeonContent.forEach((e=>{e.addEventListener("click",accordeon)}));